import React, { useState } from 'react';
import {
  Container,
  Paper,
  Typography,
  Box,
  Button,
  Grid,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Alert,
  Divider,
  CircularProgress
} from '@mui/material';
import {
  Gavel as GavelIcon,
  Save as SaveIcon,
  VerifiedUser as VerifyIcon
} from '@mui/icons-material';

const TrustAnchor = () => {
  const [config, setConfig] = useState({
    anchorName: 'Marty Trust Anchor',
    domain: 'trust.marty.local',
    policy: 'strict',
    logLevel: 'info'
  });
  const [saved, setSaved] = useState(false);

  // Verification state
  const [entityId, setEntityId] = useState('');
  const [verificationResult, setVerificationResult] = useState(null);
  const [verifying, setVerifying] = useState(false);

  const handleChange = (prop) => (event) => {
    setConfig({ ...config, [prop]: event.target.value });
    setSaved(false);
  };

  const handleSave = () => {
    // Mock save for config as backend doesn't support it yet
    setSaved(true);
    setTimeout(() => setSaved(false), 3000);
  };

  const handleVerify = async () => {
    if (!entityId) return;
    setVerifying(true);
    setVerificationResult(null);

    try {
      const response = await fetch('/api/admin/trust-anchor/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ entity_id: entityId })
      });

      const data = await response.json();

      if (!response.ok) throw new Error(data.detail || 'Verification failed');

      setVerificationResult({
        success: true,
        isTrusted: data.is_trusted,
        message: data.is_trusted ? 'Entity is trusted.' : 'Entity is NOT trusted.'
      });
    } catch (err) {
      setVerificationResult({
        success: false,
        message: err.message
      });
    } finally {
      setVerifying(false);
    }
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ mb: 4 }}>
        <Typography variant="h4" component="h1" gutterBottom>
          <GavelIcon sx={{ mr: 2, verticalAlign: 'middle' }} />
          Trust Anchor Configuration
        </Typography>
        <Typography variant="subtitle1" color="text.secondary">
          Manage Trust Anchor Settings and Policies
        </Typography>
      </Box>

      <Grid container spacing={3}>
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 3, mb: 3 }}>
            <Typography variant="h6" gutterBottom>
              Verify Entity Trust
            </Typography>
            <Divider sx={{ mb: 3 }} />
            <Grid container spacing={2} alignItems="center">
              <Grid item xs={8}>
                <TextField
                  fullWidth
                  label="Entity ID (DID or Subject)"
                  value={entityId}
                  onChange={(e) => setEntityId(e.target.value)}
                  placeholder="did:web:example.com"
                />
              </Grid>
              <Grid item xs={4}>
                <Button
                  fullWidth
                  variant="contained"
                  color="secondary"
                  startIcon={verifying ? <CircularProgress size={20} color="inherit" /> : <VerifyIcon />}
                  onClick={handleVerify}
                  disabled={!entityId || verifying}
                >
                  {verifying ? 'Verifying...' : 'Verify Trust'}
                </Button>
              </Grid>
            </Grid>

            {verificationResult && (
              <Alert 
                severity={verificationResult.success ? (verificationResult.isTrusted ? 'success' : 'warning') : 'error'} 
                sx={{ mt: 2 }}
              >
                {verificationResult.message}
              </Alert>
            )}
          </Paper>

          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              General Configuration
            </Typography>
            <Divider sx={{ mb: 3 }} />

            <Grid container spacing={3}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="Trust Anchor Name"
                  value={config.anchorName}
                  onChange={handleChange('anchorName')}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="Domain"
                  value={config.domain}
                  onChange={handleChange('domain')}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <FormControl fullWidth>
                  <InputLabel>Validation Policy</InputLabel>
                  <Select
                    value={config.policy}
                    label="Validation Policy"
                    onChange={handleChange('policy')}
                  >
                    <MenuItem value="strict">Strict (RFC 5280)</MenuItem>
                    <MenuItem value="lenient">Lenient (Dev Mode)</MenuItem>
                    <MenuItem value="custom">Custom</MenuItem>
                  </Select>
                </FormControl>
              </Grid>
              <Grid item xs={12} md={6}>
                <FormControl fullWidth>
                  <InputLabel>Log Level</InputLabel>
                  <Select
                    value={config.logLevel}
                    label="Log Level"
                    onChange={handleChange('logLevel')}
                  >
                    <MenuItem value="debug">Debug</MenuItem>
                    <MenuItem value="info">Info</MenuItem>
                    <MenuItem value="warn">Warning</MenuItem>
                    <MenuItem value="error">Error</MenuItem>
                  </Select>
                </FormControl>
              </Grid>
            </Grid>

            <Box sx={{ mt: 4, display: 'flex', justifyContent: 'flex-end' }}>
              <Button
                variant="contained"
                startIcon={<SaveIcon />}
                onClick={handleSave}
              >
                Save Configuration
              </Button>
            </Box>

            {saved && (
              <Alert severity="success" sx={{ mt: 2 }}>
                Configuration saved successfully.
              </Alert>
            )}
          </Paper>
        </Grid>

        <Grid item xs={12} md={4}>
          <Paper sx={{ p: 3, bgcolor: 'grey.50' }}>
            <Typography variant="h6" gutterBottom>
              Trust Chain Status
            </Typography>
            <Divider sx={{ mb: 2 }} />
            <Typography variant="body2" paragraph>
              <strong>Root CA:</strong> Valid (Expires 2035)
            </Typography>
            <Typography variant="body2" paragraph>
              <strong>Intermediate CA:</strong> Valid (Expires 2030)
            </Typography>
            <Typography variant="body2" paragraph>
              <strong>CRL Status:</strong> Up to date
            </Typography>
            <Alert severity="info" sx={{ mt: 2 }}>
              Trust chain is healthy and operational.
            </Alert>
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default TrustAnchor;
